"use client"

import * as React from "react"
import { cn } from "@/lib/utils"

export function dataWorkspaceTypeBadgeClassName(type?: string): string {
  const normalizedType = (type ?? "text").toLowerCase()

  if (normalizedType === "enum" || normalizedType === "select") {
    return "border-amber-300/60 bg-amber-500/10 text-amber-700 dark:text-amber-300"
  }

  if (normalizedType === "uuid" || normalizedType === "foreign-key" || normalizedType === "link") {
    return "border-sky-300/60 bg-sky-500/10 text-sky-700 dark:text-sky-300"
  }

  if (normalizedType === "datetime" || normalizedType === "date") {
    return "border-violet-300/60 bg-violet-500/10 text-violet-700 dark:text-violet-300"
  }

  if (normalizedType === "boolean") {
    return "border-emerald-300/60 bg-emerald-500/10 text-emerald-700 dark:text-emerald-300"
  }

  if (normalizedType === "json") {
    return "border-rose-300/60 bg-rose-500/10 text-rose-700 dark:text-rose-300"
  }

  return "border-border/70 bg-muted/45 text-muted-foreground"
}

export function dataWorkspaceMetaBadgeClassName(tone: "default" | "primary" | "success" | "danger" = "default"): string {
  if (tone === "primary") {
    return "border-border/70 bg-foreground/[0.06] text-foreground"
  }

  if (tone === "success") {
    return "border-emerald-300/60 bg-emerald-500/10 text-emerald-700 dark:text-emerald-300"
  }

  if (tone === "danger") {
    return "border-destructive/25 bg-destructive/10 text-destructive"
  }

  return "border-border/70 bg-background/70 text-muted-foreground"
}

export function dataWorkspaceRelationBadgeClassName(source?: string): string {
  if (source === "base") {
    return "border-border/70 bg-background/80 text-foreground"
  }

  return "border-border/70 bg-muted/50 text-muted-foreground"
}

export function dataWorkspaceRowClassName(options?: {
  interactive?: boolean
  selected?: boolean
}): string {
  return cn(
    "group border-b transition-colors",
    options?.interactive && "cursor-pointer hover:bg-muted/50",
    options?.selected && "bg-muted hover:bg-muted/70",
  )
}

export interface DataWorkspaceHeaderProps {
  eyebrow?: React.ReactNode
  title: React.ReactNode
  description?: React.ReactNode
  meta?: React.ReactNode
  actions?: React.ReactNode
  className?: string
}

export function DataWorkspaceHeader({
  eyebrow,
  title,
  description,
  meta,
  actions,
  className,
}: DataWorkspaceHeaderProps) {
  return (
    <div className={cn("flex flex-col gap-1.5 sm:flex-row sm:items-center sm:justify-between", className)}>
      <div className="min-w-0 space-y-1">
        <div className="space-y-1">
          {eyebrow ? (
            <p className="text-xs font-medium text-muted-foreground">
              {eyebrow}
            </p>
          ) : null}
          <h3 className="text-lg font-semibold leading-none tracking-tight">
            {title}
          </h3>
          {description ? (
            <p className="text-sm text-muted-foreground">
              {description}
            </p>
          ) : null}
        </div>
        {meta ? (
          <div className="flex flex-wrap items-center gap-1.5 text-xs text-muted-foreground pt-1">
            {meta}
          </div>
        ) : null}
      </div>
      {actions ? (
        <div className="flex shrink-0 flex-wrap items-center gap-2">
          {actions}
        </div>
      ) : null}
    </div>
  )
}

type DataStateTone = "neutral" | "danger" | "success"

export interface DataWorkspaceStateProps extends React.HTMLAttributes<HTMLDivElement> {
  tone?: DataStateTone
  heading?: React.ReactNode
  description: React.ReactNode
}

export function DataWorkspaceState({
  tone = "neutral",
  heading,
  description,
  className,
  ...props
}: DataWorkspaceStateProps) {
  return (
    <div
      className={cn(
        "rounded-lg border p-4 text-sm",
        tone === "danger" && "border-destructive/50 bg-destructive/10 text-destructive",
        tone === "success" && "border-emerald-500/30 bg-emerald-500/10 text-emerald-700 dark:text-emerald-300",
        tone === "neutral" && "border-dashed text-muted-foreground",
        className,
      )}
      {...props}
    >
      <div className="grid gap-1">
        {heading ? (
          <p className="font-medium text-foreground">{heading}</p>
        ) : null}
        <div className={tone === "neutral" ? "text-muted-foreground" : undefined}>
          {description}
        </div>
      </div>
    </div>
  )
}

"use client"

import * as React from "react"
import type { LemmaClient } from "lemma-sdk"
import { useRecord } from "lemma-sdk/react"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import { Card, CardContent, CardHeader } from "@/components/ui/card"
import {
  Sheet,
  SheetContent,
  SheetDescription,
  SheetHeader,
  SheetTitle,
} from "@/components/ui/sheet"
import {
  DataWorkspaceHeader,
  DataWorkspaceState,
  dataWorkspaceMetaBadgeClassName,
} from "@/components/lemma/registry-data-workspace"
import { cn } from "@/lib/utils"

type LemmaRecordDetailsVariant = "card" | "sheet"
type LemmaRecordDetailsSide = "top" | "right" | "bottom" | "left"

export interface LemmaRecordDetailsCardProps extends React.HTMLAttributes<HTMLDivElement> {
  client: LemmaClient
  podId?: string
  tableName: string
  recordId?: string | null
  fields?: string[]
  title?: string
  description?: string
  variant?: LemmaRecordDetailsVariant
  side?: LemmaRecordDetailsSide
  open?: boolean
  onOpenChange?: (open: boolean) => void
}

function sentenceCase(value: string): string {
  return value
    .replace(/_/g, " ")
    .replace(/\s+/g, " ")
    .trim()
    .replace(/\b\w/g, (match) => match.toUpperCase())
}

function formatValue(value: unknown): string {
  if (typeof value === "string") return value
  if (typeof value === "number" || typeof value === "boolean") return String(value)
  if (value === null || typeof value === "undefined") return "\u2014"

  try {
    return JSON.stringify(value, null, 2)
  } catch {
    return String(value)
  }
}

export const LemmaRecordDetailsCard = React.forwardRef<HTMLDivElement, LemmaRecordDetailsCardProps>(
  ({
    client,
    podId,
    tableName,
    recordId,
    fields,
    title,
    description,
    variant = "card",
    side = "right",
    open,
    onOpenChange,
    className,
    ...props
  }, ref) => {
    const trimmedTableName = tableName.trim()
    const trimmedRecordId = typeof recordId === "string" ? recordId.trim() : ""
    const recordKey = `${trimmedTableName}:${trimmedRecordId}`
    const [dismissedRecordKey, setDismissedRecordKey] = React.useState<string | null>(null)
    const recordState = useRecord({
      client,
      podId,
      tableName: trimmedTableName,
      recordId: trimmedRecordId || null,
      enabled: trimmedTableName.length > 0 && trimmedRecordId.length > 0,
    })

    const visibleFields = React.useMemo(() => {
      const record = recordState.record
      if (!record) return fields ?? []
      if (fields?.length) return fields
      return Object.keys(record)
        .filter((field) => field !== "created_at" && field !== "updated_at")
        .slice(0, 12)
    }, [fields, recordState.record])

    React.useEffect(() => {
      setDismissedRecordKey(null)
    }, [recordKey])

    const resolvedOpen = variant === "sheet"
      ? typeof open === "boolean"
        ? open
        : trimmedRecordId.length > 0 && dismissedRecordKey !== recordKey
      : false

    const handleOpenChange = React.useCallback((nextOpen: boolean) => {
      if (!nextOpen && typeof open !== "boolean") {
        setDismissedRecordKey(recordKey)
      }
      onOpenChange?.(nextOpen)
    }, [onOpenChange, open, recordKey])

    const headerTitle = title ?? "Record Details"
    const headerDescription = description ?? "Inspect the selected record with real values."
    const meta = (
      <div className="flex flex-wrap items-center gap-2">
        <Badge
          className={cn("rounded-full border px-2 py-0.5 text-xs", dataWorkspaceMetaBadgeClassName("default"))}
          variant="outline"
        >
          {trimmedTableName}
        </Badge>
        <Badge
          className={cn("rounded-full border px-2 py-0.5 text-xs", dataWorkspaceMetaBadgeClassName("default"))}
          variant="outline"
        >
          {visibleFields.length} field{visibleFields.length === 1 ? "" : "s"}
        </Badge>
        <Badge
          className={cn("rounded-full border px-2 py-0.5 text-xs max-w-full truncate font-mono text-[10px]", dataWorkspaceMetaBadgeClassName("primary"))}
          variant="outline"
        >
          {trimmedRecordId}
        </Badge>
      </div>
    )
    const actions = (
      <Button
        disabled={recordState.isLoading}
        onClick={() => {
          void recordState.refresh()
        }}
        type="button"
        variant="outline"
      >
        {recordState.isLoading ? "Refreshing\u2026" : "Refresh"}
      </Button>
    )

    const detailsBody = (
      <div className="flex min-h-0 flex-1 flex-col">
        <CardHeader className="p-6">
          <DataWorkspaceHeader
            actions={actions}
            description={headerDescription}
            meta={meta}
            title={headerTitle}
          />
        </CardHeader>
        <CardContent className="min-h-0 flex-1 overflow-y-auto p-6 pt-0">
          <div className="grid gap-4">
            {recordState.error ? (
              <DataWorkspaceState description={recordState.error.message} heading="Failed to load record" tone="danger" />
            ) : null}

            {recordState.isLoading && !recordState.record ? (
              <DataWorkspaceState description="Loading record details\u2026" />
            ) : null}

            {recordState.record ? (
              <div className="grid gap-3 md:grid-cols-2">
                {visibleFields.map((field) => (
                  <section
                    key={field}
                    className="rounded-lg border bg-muted/50 p-4 grid gap-3"
                  >
                    <div className="flex items-center justify-between gap-3">
                      <div className="text-sm font-medium text-foreground">{sentenceCase(field)}</div>
                      <Badge
                        className={cn("rounded-full border px-2 py-0.5 text-xs font-mono", dataWorkspaceMetaBadgeClassName("default"))}
                        variant="outline"
                      >
                        {field}
                      </Badge>
                    </div>
                    <pre className="overflow-x-auto whitespace-pre-wrap break-words text-sm leading-6 text-muted-foreground">
                      {formatValue(recordState.record?.[field])}
                    </pre>
                  </section>
                ))}
              </div>
            ) : null}
          </div>
        </CardContent>
      </div>
    )

    if (!trimmedTableName || !trimmedRecordId) {
      if (variant === "sheet") {
        return null
      }

      return (
        <div ref={ref} className={cn("rounded-lg border bg-card text-card-foreground shadow-sm", className)} {...props}>
          <CardHeader className="p-6">
            <DataWorkspaceHeader
              description={description ?? "Select a record to inspect its full payload."}
              title={headerTitle}
            />
          </CardHeader>
        </div>
      )
    }

    if (variant === "sheet") {
      return (
        <Sheet open={resolvedOpen} onOpenChange={handleOpenChange}>
          <SheetContent className="flex w-full flex-col gap-0 p-0 border-l border-border/60 sm:max-w-2xl" side={side}>
            <SheetHeader className="sr-only">
              <SheetTitle>{headerTitle}</SheetTitle>
              <SheetDescription>{headerDescription}</SheetDescription>
            </SheetHeader>
            {detailsBody}
          </SheetContent>
        </Sheet>
      )
    }

    return (
      <div ref={ref} className={cn("rounded-lg border bg-card text-card-foreground shadow-sm", className)} {...props}>
        {detailsBody}
      </div>
    )
  },
)
LemmaRecordDetailsCard.displayName = "LemmaRecordDetailsCard"
